import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void classic() {
        int[] result = new Solution().kSmallest(new int[]{50, 10, 30, 10, 50}, 3);
        assertArrayEquals(new int[]{10, 10, 30}, result);
    }

    @Test
    void kEqualsOne() {
        int[] result = new Solution().kSmallest(new int[]{20, 5, 80}, 1);
        assertArrayEquals(new int[]{5}, result);
    }

    @Test
    void kGreaterThanLength() {
        // collect all; sorted ascending
        int[] result = new Solution().kSmallest(new int[]{20, 5, 80}, 5);
        assertArrayEquals(new int[]{5, 20, 80}, result);
    }

    @Test
    void empty() {
        int[] result = new Solution().kSmallest(new int[]{}, 3);
        assertArrayEquals(new int[]{}, result);
    }

    @Test
    void boundarValues() {
        // values at bucket extremes: 0 and 100
        int[] result = new Solution().kSmallest(new int[]{100, 0, 100, 0, 50}, 3);
        assertArrayEquals(new int[]{0, 0, 50}, result);
    }

    @Test
    void allSameValue() {
        // all in one bucket; take k of them
        int[] result = new Solution().kSmallest(new int[]{7, 7, 7, 7, 7}, 3);
        assertArrayEquals(new int[]{7, 7, 7}, result);
    }

    @Test
    void kEqualsLength() {
        // exact fit: return all sorted
        int[] result = new Solution().kSmallest(new int[]{3, 1, 2}, 3);
        assertArrayEquals(new int[]{1, 2, 3}, result);
    }
}
